module sram_cell (  
    input wire [7:0] data_in,  
    input wire read_en,  
    input wire write_en,  
    input wire clk,  
    output reg [7:0] data_out  
);  
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    reg [7:0] memory;  

    always @(posedge clk) begin  
        if (write_en) begin  
            memory <= data_in;  
        end  
    end  

    always @(posedge clk) begin  
        if (read_en) begin  
            data_out <= memory;  
        end  
    end  
endmodule
